mutation StandardMetafieldDefinitionEnableDeprecatedAccessFilter {
  standardMetafieldDefinitionEnable(
    ownerType: PRODUCT
    id: "gid://shopify/StandardMetafieldDefinitionTemplate/3"
    useAsAdminFilter: true
    visibleToStorefrontApi: false
  ) {
    createdDefinition {
      namespace
      key
      access {
        storefront
